module RefModule(clk, rst_n, out);input clk, rst_n;
    output [3:0] out;

    reg [3:0] unused_count;

    always @(posedge clk, negedge rst_n) begin
        if(!rst_n) begin
            unused_count <= 4'b0;
        end else begin
            if(unused_count == 4'b1111) begin
                unused_count <= 4'b0;
            end else begin
                unused_count <= unused_count + 1;
            end
        end
    end

    assign out = unused_count;

endmodule
